  const [status, setStatus] = useState<Status>('idle');
  const [error, setError] = useState<string | null>(null);
  const [isGeneratingPrompt, setIsGeneratingPrompt] = useState(false);
  const [downloadUrl, setDownloadUrl] = useState<string | null>(null);
  const [isProcessingDownload, setIsProcessingDownload] = useState(false);
  const [isGuideOpen, setIsGuideOpen] = useState(false);
  const [selectedInstruments, setSelectedInstruments] = useState<string[]>([]);
  const [isAddingInstrument, setIsAddingInstrument] = useState(false);

  const [musicConfig, setMusicConfig] = useState<MusicConfig>({
    bpm: 120,
    density: 0.5,
    brightness: 0.5,
    guidance: 4.0,
  });

  const [effectType, setEffectType] = useState<EffectType>('none');
  const [effectIntensity, setEffectIntensity] = useState(0.3); // Wet/Dry mix

  const sessionRef = useRef<LiveMusicSession | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef<number>(0);
  const audioChunksRef = useRef<AudioBuffer[]>([]);

  // Audio effects nodes
  const dryNodeRef = useRef<GainNode | null>(null);
  const wetNodeRef = useRef<GainNode | null>(null);
  const convolverNodeRef = useRef<ConvolverNode | null>(null); // Reverb
  const delayNodeRef = useRef<DelayNode | null>(null); // Echo
  const feedbackNodeRef = useRef<GainNode | null>(null); // Echo feedback
  const masterGainNodeRef = useRef<GainNode | null>(null);

  const statusRef = useRef(status);
  useEffect(() => {
    statusRef.current = status;
  }, [status]);

  const isBusy = status === 'connecting' || status === 'generating' || status === 'stopping';

  useEffect(() => {
    const url = downloadUrl;
    return () => {
        if (url) {
            URL.revokeObjectURL(url);
        }
    };
  }, [downloadUrl]);

  const cleanupAudio = useCallback(() => {
    if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
      sourcesRef.current.forEach(source => {
        try {
            source.stop();
        } catch (e) {
            console.warn("Could not stop source", e);
        }
      });
      sourcesRef.current.clear();
      audioContextRef.current.close().catch(console.error);
    }
    audioContextRef.current = null;
    analyserRef.current = null;
    masterGainNodeRef.current = null;
    nextStartTimeRef.current = 0;
  }, []);

  const handleStop = useCallback(async () => {
    setStatus('stopping');
    if (sessionRef.current) {
      await closeSession(sessionRef.current);
      sessionRef.current = null;
    }

    if (audioChunksRef.current.length > 0) {
        setIsProcessingDownload(true);
        try {
            const concatenatedBuffer = concatenateAudioBuffers(audioChunksRef.current);
            if (concatenatedBuffer) {
                const wavBlob = audioBufferToWav(concatenatedBuffer);
                const url = URL.createObjectURL(wavBlob);
                setDownloadUrl(url);
            }
        } catch (e) {
            console.error("Failed to create download file:", e);
            setError("Could not process audio for download.");
        } finally {
            setIsProcessingDownload(false);
        }
    }

    cleanupAudio();
    setStatus('idle');
  }, [cleanupAudio]);

  const handleGenerate = useCallback(async () => {
    if (isBusy) return;
    setError(null);
    setDownloadUrl(null);
    setStatus('connecting');
    audioChunksRef.current = [];

    try {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 48000 });

      // Master Gain
      masterGainNodeRef.current = audioContext.createGain();

      // Analyser
      const analyser = audioContext.createAnalyser();
      analyser.fftSize = 256;
      masterGainNodeRef.current.connect(analyser);
      analyser.connect(audioContext.destination);

      // Effect nodes setup
      dryNodeRef.current = audioContext.createGain();
      wetNodeRef.current = audioContext.createGain();
      dryNodeRef.current.connect(masterGainNodeRef.current);
      wetNodeRef.current.connect(masterGainNodeRef.current);

      // Reverb
      convolverNodeRef.current = audioContext.createConvolver();
      const impulseResponse = await createReverbImpulseResponse(audioContext);
      convolverNodeRef.current.buffer = impulseResponse;

      // Echo
      delayNodeRef.current = audioContext.createDelay(1.0); // Max 1s delay
      feedbackNodeRef.current = audioContext.createGain();
      delayNodeRef.current.connect(feedbackNodeRef.current);
      feedbackNodeRef.current.connect(delayNodeRef.current);

      audioContextRef.current = audioContext;
      analyserRef.current = analyser;
      nextStartTimeRef.current = 0;
      sourcesRef.current.clear();

      const newSession = await startSession({
        prompt: finalPrompt,
        config: musicConfig,
        onAudioChunk: (audioBuffer) => {
          if (!audioContextRef.current || !masterGainNodeRef.current || !dryNodeRef.current) return;

          audioChunksRef.current.push(audioBuffer);

          const source = audioContextRef.current.createBufferSource();
          source.buffer = audioBuffer;
          // Connect source to both dry and wet paths
          source.connect(dryNodeRef.current);
          source.connect(wetNodeRef.current);

          source.onended = () => {
            sourcesRef.current.delete(source);
          };

          const currentTime = audioContextRef.current.currentTime;
          const startTime = Math.max(currentTime, nextStartTimeRef.current);
          source.start(startTime);
          nextStartTimeRef.current = startTime + audioBuffer.duration;
          sourcesRef.current.add(source);
        },
        onOpen: () => {
          setStatus('generating');
        },
        onError: (err: ErrorEvent) => {
          console.error('Session error:', err);
          setError(`An error occurred: ${err.message}. This might be an experimental feature. Please try again.`);
          setStatus('error');
          handleStop();
        },
        onClose: (_event: CloseEvent) => {
          if (statusRef.current !== 'stopping') {
            handleStop();
          }
        },
      });
      sessionRef.current = newSession;

    } catch (err: any) {
      console.error('Failed to start session:', err);
      setError(`Failed to start session: ${err.message}`);
      setStatus('error');
      cleanupAudio();
    }
  }, [finalPrompt, isBusy, cleanupAudio, handleStop, musicConfig]);

  const handleSurpriseMe = async () => {
    setIsGeneratingPrompt(true);
    setError(null);
    try {
        const newPrompt = await generateSurprisePrompt();
        setPrompt(newPrompt);
    } catch (err: any) {
        setError(`Failed to generate prompt: ${err.message}`);
    } finally {
        setIsGeneratingPrompt(false);
    }
  };

  const toggleInstrument = (instrument: string) => {
      setSelectedInstruments(prev => 
          prev.includes(instrument) 
              ? prev.filter(i => i !== instrument) 
              : [...prev, instrument]
      );
      setIsAddingInstrument(false);
  };

  useEffect(() => {
    const instrumentText = selectedInstruments.length > 0
        ? ` with the following instruments: ${selectedInstruments.join(', ')}.`
        : '';
    setFinalPrompt(prompt + instrumentText);
  }, [prompt, selectedInstruments]);


  useEffect(() => {
    if (status === 'generating' && sessionRef.current) {
        updateMusicConfig(sessionRef.current, musicConfig);
    }
  }, [musicConfig, status]);

  useEffect(() => {
    const handler = setTimeout(() => {
        if (status === 'generating' && sessionRef.current && finalPrompt) {
            updatePrompt(sessionRef.current, finalPrompt);
        }
    }, 500); // Debounce prompt updates

    return () => {
        clearTimeout(handler);
    };
  }, [finalPrompt, status]);

  // Effect routing logic
  useEffect(() => {
    if (status !== 'generating' || !wetNodeRef.current || !dryNodeRef.current || !masterGainNodeRef.current) return;

    // Disconnect all wet paths first
    wetNodeRef.current.disconnect();
    convolverNodeRef.current?.disconnect();
    delayNodeRef.current?.disconnect();
    feedbackNodeRef.current?.disconnect(delayNodeRef.current);

    // Set gains based on intensity (wet/dry mix)
    dryNodeRef.current.gain.setValueAtTime(1 - effectIntensity, audioContextRef.current!.currentTime);
    wetNodeRef.current.gain.setValueAtTime(effectIntensity, audioContextRef.current!.currentTime);

    if (effectType === 'reverb' && convolverNodeRef.current) {
        wetNodeRef.current.connect(convolverNodeRef.current);
        convolverNodeRef.current.connect(masterGainNodeRef.current);
    } else if (effectType === 'echo' && delayNodeRef.current && feedbackNodeRef.current) {
        // Intensity controls feedback and delay time for echo
        feedbackNodeRef.current.gain.setValueAtTime(effectIntensity * 0.7, audioContextRef.current!.currentTime); // 0.7 to avoid harsh feedback
        delayNodeRef.current.delayTime.setValueAtTime(effectIntensity * 0.5 + 0.1, audioContextRef.current!.currentTime); // 0.1s to 0.6s delay

        wetNodeRef.current.connect(delayNodeRef.current);
        delayNodeRef.current.connect(masterGainNodeRef.current);
        feedbackNodeRef.current.connect(delayNodeRef.current);
    } else {
        // No effect, set wet gain to 0
        wetNodeRef.current.gain.setValueAtTime(0, audioContextRef.current!.currentTime);
        dryNodeRef.current.gain.setValueAtTime(1, audioContextRef.current!.currentTime);
    }

  }, [effectType, effectIntensity, status]);

  return (
    <div className="min-h-screen bg-gradient-to-br from-red-500 via-orange-500 to-amber-500 flex flex-col items-center justify-center p-4 font-sans text-white overflow-hidden relative">
      <PromptGuideModal isOpen={isGuideOpen} onClose={() => setIsGuideOpen(false)} />

      {/* Background Blobs for depth */}
      <div className="absolute top-20 left-20 w-72 h-72 bg-orange-600 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob"></div>
      <div className="absolute top-40 right-20 w-72 h-72 bg-red-600 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-2000"></div>
      <div className="absolute -bottom-8 left-40 w-72 h-72 bg-amber-600 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-4000"></div>

      <div className="w-full max-w-4xl relative z-10 flex flex-col h-[85vh]">

        {/* Main Glass Card */}
        <div className="flex-1 bg-white/10 backdrop-blur-xl border border-white/20 rounded-3xl shadow-2xl overflow-y-auto flex flex-col">

            <header className="p-6 md:p-8 border-b border-white/10 flex justify-between items-start">
               <div>
                 <h1 className="text-2xl font-bold text-white tracking-tight">Create a track</h1>
                 <p className="text-white/60 text-sm mt-1">Experiment with prompt, style, and instruments.</p>
               </div>
               <button onClick={() => setIsGuideOpen(true)} className="p-2 hover:bg-white/10 rounded-full transition-colors text-white/80">
                  <InfoIcon />
               </button>
            </header>

            <div className="p-6 md:p-8 space-y-8 flex-1">
                {error && (
                    <div className="bg-red-500/20 border border-red-500/40 text-red-100 px-4 py-3 rounded-xl text-sm backdrop-blur-sm">
                        {error}
                    </div>
                )}

                {/* Main Input Area */}
                <div className="relative group">
                    <textarea
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                        placeholder="Describe your sound..."
                        className="w-full bg-transparent text-3xl md:text-5xl font-bold text-white placeholder-white/30 focus:outline-none resize-none leading-tight"
                        rows={2}
                        disabled={isBusy}
                    />
                    <button 
                        onClick={handleSurpriseMe}
                        disabled={isBusy || isGeneratingPrompt}
                        className="absolute right-0 bottom-2 text-sm text-white/60 hover:text-white flex items-center gap-1 bg-white/10 px-3 py-1.5 rounded-full backdrop-blur-md transition-all hover:bg-white/20 disabled:opacity-50"
                    >
                        {isGeneratingPrompt ? <LoadingIcon /> : <MagicWandIcon />}
                        Surprise Me
                    </button>
                </div>

                {/* Floating Pills Container */}
                <div className="flex flex-wrap gap-4 items-center">

                    {/* Instrument Pills */}
                    {selectedInstruments.map(inst => (
                        <div key={inst} className="group flex items-center gap-2 bg-orange-500/40 border border-orange-400/50 backdrop-blur-md text-white px-4 py-2 rounded-full shadow-lg hover:bg-orange-500/60 transition-all cursor-default animate-fade-in-up">
                            <span className="font-medium text-sm">{inst}</span>
                            <button 
                                onClick={() => toggleInstrument(inst)} 
                                disabled={isBusy}
                                className="text-orange-200 hover:text-white focus:outline-none"
                            >
                                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                            </button>
                        </div>
                    ))}

                    {/* Add Instrument Button */}
                    <div className="relative">
                        <button 
                            onClick={() => setIsAddingInstrument(!isAddingInstrument)}
                            disabled={isBusy}
                            className="flex items-center gap-2 bg-white/5 border border-white/10 hover:bg-white/10 hover:border-white/30 text-white/80 px-4 py-2 rounded-full transition-all text-sm font-medium border-dashed"
                        >
                           <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                           Add Instrument
                        </button>

                        {isAddingInstrument && (
                            <div className="absolute top-full left-0 mt-2 w-48 bg-gray-800/90 backdrop-blur-xl border border-white/10 rounded-xl shadow-2xl z-50 max-h-60 overflow-y-auto">
                                {INSTRUMENT_LIST.filter(i => !selectedInstruments.includes(i)).map(inst => (
                                    <button
                                        key={inst}
                                        onClick={() => toggleInstrument(inst)}
                                        className="w-full text-left px-4 py-2 text-sm text-white/80 hover:bg-white/10 hover:text-white transition-colors"
                                    >
                                        {inst}
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>

                    <div className="w-full h-px bg-white/10 my-2"></div>

                    {/* Parameter Sliders as Pills */}
                    <Slider label="BPM" min={60} max={200} step={1} value={musicConfig.bpm} onChange={v => setMusicConfig(c => ({...c, bpm: Math.round(v)}))} disabled={isBusy} />
                    <Slider label="Density" min={0} max={1} step={0.01} value={musicConfig.density} onChange={v => setMusicConfig(c => ({...c, density: v}))} disabled={isBusy} />
                    <Slider label="Guidance" min={0} max={6} step={0.1} value={musicConfig.guidance} onChange={v => setMusicConfig(c => ({...c, guidance: v}))} disabled={isBusy} />

                    {/* Effect Control Pill */}
                    <div className="flex items-center gap-2 bg-white/10 backdrop-blur-md rounded-full px-4 py-2 border border-white/20 shadow-sm">
                        <select 
                            value={effectType}
                            onChange={e => setEffectType(e.target.value as EffectType)}
                            disabled={!isBusy}
                            className="bg-transparent text-xs font-medium text-white/90 focus:outline-none cursor-pointer [&>option]:bg-gray-800"
                        >
                            <option value="none">No Effect</option>
                            <option value="reverb">Reverb</option>
                            <option value="echo">Echo</option>
                        </select>
                         {effectType !== 'none' && (
                             <input 
                                type="range" 
                                min={0} max={1} step={0.01} 
                                value={effectIntensity} 
                                onChange={e => setEffectIntensity(parseFloat(e.target.value))}
                                className="w-16 h-1.5 bg-white/30 rounded-lg appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:h-3 [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-white"
                             />
                         )}
                    </div>

                </div>
            </div>

            {/* Bottom Player Bar */}
            <div className="p-4 md:p-6 bg-transparent">
                <div className="bg-black/80 backdrop-blur-2xl border border-white/10 rounded-full h-20 md:h-24 px-6 md:px-8 flex items-center gap-6 shadow-2xl relative z-20">

                    {/* Play/Stop Controls */}
                    <div className="flex items-center gap-4">
                        {status === 'generating' || status === 'connecting' ? (
                             <button onClick={handleStop} className="w-12 h-12 md:w-14 md:h-14 bg-white text-black rounded-full flex items-center justify-center hover:scale-105 transition-transform shadow-lg shadow-white/20">
                                {status === 'connecting' ? <LoadingIcon /> : <StopIcon />}
                             </button>
                        ) : (
                             <button onClick={handleGenerate} disabled={!prompt} className="w-12 h-12 md:w-14 md:h-14 bg-white text-black rounded-full flex items-center justify-center hover:scale-105 transition-transform shadow-lg shadow-white/20 disabled:opacity-50 disabled:scale-100 disabled:cursor-not-allowed">
                                <PlayIcon />
                             </button>
                        )}

                        <button 
                            onClick={handleSurpriseMe} 
                            disabled={isBusy || isGeneratingPrompt}
                            className="p-3 text-white/50 hover:text-white hover:bg-white/10 rounded-full transition-all hidden md:block"
                            title="New Random Prompt"
                        >
                            <RefreshIcon />
                        </button>
                    </div>

                    {/* Visualizer Area */}
                    <div className="flex-1 h-full flex items-center justify-center overflow-hidden py-3">
                         {status === 'generating' && analyserRef.current ? (
                            <AudioVisualizer analyserNode={analyserRef.current} />
                         ) : (
                             <div className="flex items-center gap-1 h-8">
                                 {[...Array(20)].map((_, i) => (
                                     <div key={i} className="w-1.5 bg-white/10 rounded-full" style={{height: `${Math.random() * 40 + 20}%`}}></div>
                                 ))}
                             </div>
                         )}
                    </div>

                     {/* Download / Status Actions */}
                     <div className="flex items-center gap-4">
                        {isProcessingDownload ? (
                            <div className="w-10 h-10 flex items-center justify-center text-white/50"><LoadingIcon /></div>
                        ) : downloadUrl ? (
                             <a
                                href={downloadUrl}
                                download="gemini-music.wav"
                                className="p-3 bg-white/10 text-white rounded-full hover:bg-white/20 transition-colors"
                                title="Download WAV"
                            >
                                <DownloadIcon />
                            </a>
                        ) : null}
                     </div>

                </div>
            </div>
        </div>

        <p className="text-center text-white/40 text-xs mt-4">Powered by Gemini Live API</p>
      </div>
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';

interface AudioVisualizerProps {
  analyserNode: AnalyserNode;
}

const AudioVisualizer: React.FC<AudioVisualizerProps> = ({ analyserNode }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameRef = useRef<number | null>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const canvasCtx = canvas.getContext('2d');
    if (!canvasCtx) return;

    const draw = () => {
      animationFrameRef.current = requestAnimationFrame(draw);

      const bufferLength = analyserNode.frequencyBinCount;
      const dataArray = new Uint8Array(bufferLength);
      analyserNode.getByteFrequencyData(dataArray);

      canvasCtx.clearRect(0, 0, canvas.width, canvas.height);

      const barWidth = (canvas.width / bufferLength) * 2;
      let x = 0;

      // Create a gradient that matches the "neon" aesthetic of the player
      const gradient = canvasCtx.createLinearGradient(0, 0, canvas.width, 0);
      gradient.addColorStop(0, '#f97316'); // Orange-500
      gradient.addColorStop(0.5, '#ef4444'); // Red-500
      gradient.addColorStop(1, '#f59e0b'); // Amber-500

      canvasCtx.fillStyle = gradient;

      for (let i = 0; i < bufferLength; i++) {
        const barHeight = (dataArray[i] / 255) * canvas.height * 0.8; // Scale slightly

        // Center the bars vertically to look like a waveform
        const y = (canvas.height - barHeight) / 2;

        // Draw rounded bars
        canvasCtx.beginPath();
        canvasCtx.roundRect(x, y, barWidth - 1, barHeight, 2);
        canvasCtx.fill();

        x += barWidth + 1;
      }
    };

    draw();

    return () => {
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
      }
    };
  }, [analyserNode]);

  return <canvas ref={canvasRef} width="800" height="100" className="w-full h-full" />;
};

export default AudioVisualizer;

import React, { useState, useRef, useEffect } from 'react';
import { ChevronDownIcon, MusicNoteIcon } from './Icons';

interface MultiSelectProps {
  options: string[];
  selectedOptions: string[];
  onChange: (selected: string[]) => void;
  disabled?: boolean;
}

const MultiSelect: React.FC<MultiSelectProps> = ({ options, selectedOptions, onChange, disabled = false }) => {
  const [isOpen, setIsOpen] = useState(false);
  const wrapperRef = useRef<HTMLDivElement>(null);

  const toggleOption = (option: string) => {
    const newSelected = selectedOptions.includes(option)
      ? selectedOptions.filter((o) => o !== option)
      : [...selectedOptions, option];
    onChange(newSelected);
  };

  const removeOption = (e: React.MouseEvent, option: string) => {
      e.stopPropagation();
      onChange(selectedOptions.filter(o => o !== option));
  }

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  return (
    <div className="relative w-full md:w-auto" ref={wrapperRef}>
      <button
        type="button"
        onClick={() => !disabled && setIsOpen(!isOpen)}
        disabled={disabled}
        className={`w-full min-w-[200px] bg-white/5 border border-white/10 hover:bg-white/10 hover:border-white/20 transition-all rounded-xl px-4 py-2.5 text-left text-sm flex justify-between items-center disabled:opacity-50 disabled:cursor-not-allowed ${isOpen ? 'ring-2 ring-orange-500/50 border-transparent' : ''}`}
      >
        <span className="truncate text-white/80 font-medium flex items-center gap-2">
            <MusicNoteIcon />
            {selectedOptions.length === 0 ? 'Select instruments...' : `${selectedOptions.length} selected`}
        </span>
        <div className={`transition-transform duration-200 text-white/60 ${isOpen ? 'rotate-180' : ''}`}>
           <ChevronDownIcon />
        </div>
      </button>

      {/* Selected items display (Outside dropdown for cleaner look, similar to input tags) */}
      {selectedOptions.length > 0 && (
          <div className="flex flex-wrap gap-2 mt-3">
              {selectedOptions.map(option => (
                  <span key={option} className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-semibold bg-orange-500/80 text-white border border-orange-400/30 shadow-sm animate-fade-in-up">
                      {option}
                      <button 
                        onClick={(e) => removeOption(e, option)}
                        disabled={disabled}
                        className="hover:text-orange-200 focus:outline-none"
                      >
                          <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                      </button>
                  </span>
              ))}
          </div>
      )}

      {isOpen && (
        <div className="absolute z-50 w-full min-w-[240px] mt-2 bg-gray-900/95 backdrop-blur-xl border border-white/10 rounded-xl shadow-2xl max-h-60 overflow-y-auto custom-scrollbar animate-fade-in origin-top-left left-0">
          <div className="p-2 space-y-1">
            {options.map((option) => {
              const isSelected = selectedOptions.includes(option);
              return (
                <div
                  key={option}
                  onClick={() => toggleOption(option)}
                  className={`px-3 py-2 rounded-lg text-sm cursor-pointer flex items-center justify-between group transition-colors ${
                    isSelected 
                        ? 'bg-gradient-to-r from-orange-500/20 to-red-500/20 text-white' 
                        : 'text-white/70 hover:bg-white/10 hover:text-white'
                  }`}
                >
                  <span className="font-medium">{option}</span>
                  {isSelected && (
                    <span className="text-orange-400">
                      <svg className="w-4 h-4" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                      </svg>
                    </span>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
};

export default MultiSelect;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { LiveMusicSession } from '@google/genai';
import { startSession, closeSession, updateMusicConfig, updatePrompt, generateSurprisePrompt } from './services/geminiService';
import { concatenateAudioBuffers, audioBufferToWav, createReverbImpulseResponse } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { LoadingIcon, PlayIcon, StopIcon, MagicWandIcon, DownloadIcon, InfoIcon, RefreshIcon, ChevronDownIcon } from './components/Icons';
import Slider from './components/Slider';
import PromptGuideModal from './components/PromptGuideModal';
import MultiSelect from './components/MultiSelect';

type Status = 'idle' | 'connecting' | 'generating' | 'stopping' | 'error';
type EffectType = 'none' | 'reverb' | 'echo';

interface MusicConfig {
  bpm: number;
  density: number;
  brightness: number;
  guidance: number;
}

const INSTRUMENT_LIST = [
    "Piano", "Acoustic Guitar", "Electric Guitar", "Bass Guitar", "Drums", "Violin", "Cello", "Trumpet",
    "Saxophone", "Flute", "Synth Pads", "808 Bass", "Sitar", "Marimba", "Hang Drum"
];

const App: React.FC = () => {
  const [prompt, setPrompt] = useState<string>('Minimal techno with deep bass');
  const [finalPrompt, setFinalPrompt] = useState(prompt);
  const [status, setStatus] = useState<Status>('idle');
  const [error, setError] = useState<string | null>(null);
  const [isGeneratingPrompt, setIsGeneratingPrompt] = useState(false);
  const [downloadUrl, setDownloadUrl] = useState<string | null>(null);
  const [isProcessingDownload, setIsProcessingDownload] = useState(false);
  const [isGuideOpen, setIsGuideOpen] = useState(false);
  const [selectedInstruments, setSelectedInstruments] = useState<string[]>([]);

  // Export Menu State
  const [isExportMenuOpen, setIsExportMenuOpen] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);

  const [musicConfig, setMusicConfig] = useState<MusicConfig>({
    bpm: 120,
    density: 0.5,
    brightness: 0.5,
    guidance: 4.0,
  });

  const [effectType, setEffectType] = useState<EffectType>('none');
  const [effectIntensity, setEffectIntensity] = useState(0.3); // Wet/Dry mix

  const sessionRef = useRef<LiveMusicSession | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef<number>(0);
  const audioChunksRef = useRef<AudioBuffer[]>([]);

  // Audio effects nodes
  const dryNodeRef = useRef<GainNode | null>(null);
  const wetNodeRef = useRef<GainNode | null>(null);
  const convolverNodeRef = useRef<ConvolverNode | null>(null); // Reverb
  const delayNodeRef = useRef<DelayNode | null>(null); // Echo
  const feedbackNodeRef = useRef<GainNode | null>(null); // Echo feedback
  const masterGainNodeRef = useRef<GainNode | null>(null);

  const statusRef = useRef(status);
  useEffect(() => {
    statusRef.current = status;
  }, [status]);

  const isBusy = status === 'connecting' || status === 'generating' || status === 'stopping';

  useEffect(() => {
    const url = downloadUrl;
    return () => {
        if (url) {
            URL.revokeObjectURL(url);
        }
    };
  }, [downloadUrl]);

  // Handle outside click for export menu
  useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
          if (exportMenuRef.current && !exportMenuRef.current.contains(event.target as Node)) {
              setIsExportMenuOpen(false);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const cleanupAudio = useCallback(() => {
    if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
      sourcesRef.current.forEach(source => {
        try {
            source.stop();
        } catch (e) {
            console.warn("Could not stop source", e);
        }
      });
      sourcesRef.current.clear();
      audioContextRef.current.close().catch(console.error);
    }
    audioContextRef.current = null;
    analyserRef.current = null;
    masterGainNodeRef.current = null;
    nextStartTimeRef.current = 0;
  }, []);

  const handleStop = useCallback(async () => {
    setStatus('stopping');
    if (sessionRef.current) {
      await closeSession(sessionRef.current);
      sessionRef.current = null;
    }

    if (audioChunksRef.current.length > 0) {
        setIsProcessingDownload(true);
        try {
            const concatenatedBuffer = concatenateAudioBuffers(audioChunksRef.current);
            if (concatenatedBuffer) {
                const wavBlob = audioBufferToWav(concatenatedBuffer);
                const url = URL.createObjectURL(wavBlob);
                setDownloadUrl(url);
            }
        } catch (e) {
            console.error("Failed to create download file:", e);
            setError("Could not process audio for download.");
        } finally {
            setIsProcessingDownload(false);
        }
    }

    cleanupAudio();
    setStatus('idle');
  }, [cleanupAudio]);

  const handleGenerate = useCallback(async () => {
    if (isBusy) return;
    setError(null);
    setDownloadUrl(null);
    setStatus('connecting');
    audioChunksRef.current = [];

    try {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 48000 });

      // Master Gain
      masterGainNodeRef.current = audioContext.createGain();

      // Analyser
      const analyser = audioContext.createAnalyser();
      analyser.fftSize = 256;
      masterGainNodeRef.current.connect(analyser);
      analyser.connect(audioContext.destination);

      // Effect nodes setup
      dryNodeRef.current = audioContext.createGain();
      wetNodeRef.current = audioContext.createGain();
      dryNodeRef.current.connect(masterGainNodeRef.current);
      wetNodeRef.current.connect(masterGainNodeRef.current);

      // Reverb
      convolverNodeRef.current = audioContext.createConvolver();
      const impulseResponse = await createReverbImpulseResponse(audioContext);
      convolverNodeRef.current.buffer = impulseResponse;

      // Echo
      delayNodeRef.current = audioContext.createDelay(1.0); // Max 1s delay
      feedbackNodeRef.current = audioContext.createGain();
      delayNodeRef.current.connect(feedbackNodeRef.current);
      feedbackNodeRef.current.connect(delayNodeRef.current);

      audioContextRef.current = audioContext;
      analyserRef.current = analyser;
      nextStartTimeRef.current = 0;
      sourcesRef.current.clear();

      const newSession = await startSession({
        prompt: finalPrompt,
        config: musicConfig,
        onAudioChunk: (audioBuffer) => {
          if (!audioContextRef.current || !masterGainNodeRef.current || !dryNodeRef.current) return;

          audioChunksRef.current.push(audioBuffer);

          const source = audioContextRef.current.createBufferSource();
          source.buffer = audioBuffer;
          // Connect source to both dry and wet paths
          source.connect(dryNodeRef.current);
          source.connect(wetNodeRef.current);

          source.onended = () => {
            sourcesRef.current.delete(source);
          };

          const currentTime = audioContextRef.current.currentTime;
          const startTime = Math.max(currentTime, nextStartTimeRef.current);
          source.start(startTime);
          nextStartTimeRef.current = startTime + audioBuffer.duration;
          sourcesRef.current.add(source);
        },
        onOpen: () => {
          setStatus('generating');
        },
        onError: (err: ErrorEvent) => {
          console.error('Session error:', err);
          setError(`An error occurred: ${err.message}. This might be an experimental feature. Please try again.`);
          setStatus('error');
          handleStop();
        },
        onClose: (_event: CloseEvent) => {
          if (statusRef.current !== 'stopping') {
            handleStop();
          }
        },
      });
      sessionRef.current = newSession;

    } catch (err: any) {
      console.error('Failed to start session:', err);
      setError(`Failed to start session: ${err.message}`);
      setStatus('error');
      cleanupAudio();
    }
  }, [finalPrompt, isBusy, cleanupAudio, handleStop, musicConfig]);

  const handleSurpriseMe = async () => {
    setIsGeneratingPrompt(true);
    setError(null);
    try {
        const newPrompt = await generateSurprisePrompt();
        setPrompt(newPrompt);
    } catch (err: any) {
        setError(`Failed to generate prompt: ${err.message}`);
    } finally {
        setIsGeneratingPrompt(false);
    }
  };

  useEffect(() => {
    const instrumentText = selectedInstruments.length > 0
        ? ` with the following instruments: ${selectedInstruments.join(', ')}.`
        : '';
    setFinalPrompt(prompt + instrumentText);
  }, [prompt, selectedInstruments]);


  useEffect(() => {
    if (status === 'generating' && sessionRef.current) {
        updateMusicConfig(sessionRef.current, musicConfig);
    }
  }, [musicConfig, status]);

  useEffect(() => {
    const handler = setTimeout(() => {
        if (status === 'generating' && sessionRef.current && finalPrompt) {
            updatePrompt(sessionRef.current, finalPrompt);
        }
    }, 500); // Debounce prompt updates

    return () => {
        clearTimeout(handler);
    };
  }, [finalPrompt, status]);

  // Effect routing logic
  useEffect(() => {
    if (status !== 'generating' || !wetNodeRef.current || !dryNodeRef.current || !masterGainNodeRef.current) return;

    // Disconnect all wet paths first
    wetNodeRef.current.disconnect();
    convolverNodeRef.current?.disconnect();
    delayNodeRef.current?.disconnect();
    feedbackNodeRef.current?.disconnect(delayNodeRef.current);

    // Set gains based on intensity (wet/dry mix)
    dryNodeRef.current.gain.setValueAtTime(1 - effectIntensity, audioContextRef.current!.currentTime);
    wetNodeRef.current.gain.setValueAtTime(effectIntensity, audioContextRef.current!.currentTime);

    if (effectType === 'reverb' && convolverNodeRef.current) {
        wetNodeRef.current.connect(convolverNodeRef.current);
        convolverNodeRef.current.connect(masterGainNodeRef.current);
    } else if (effectType === 'echo' && delayNodeRef.current && feedbackNodeRef.current) {
        // Intensity controls feedback and delay time for echo
        feedbackNodeRef.current.gain.setValueAtTime(effectIntensity * 0.7, audioContextRef.current!.currentTime); // 0.7 to avoid harsh feedback
        delayNodeRef.current.delayTime.setValueAtTime(effectIntensity * 0.5 + 0.1, audioContextRef.current!.currentTime); // 0.1s to 0.6s delay

        wetNodeRef.current.connect(delayNodeRef.current);
        delayNodeRef.current.connect(masterGainNodeRef.current);
        feedbackNodeRef.current.connect(delayNodeRef.current);
    } else {
        // No effect, set wet gain to 0
        wetNodeRef.current.gain.setValueAtTime(0, audioContextRef.current!.currentTime);
        dryNodeRef.current.gain.setValueAtTime(1, audioContextRef.current!.currentTime);
    }

  }, [effectType, effectIntensity, status]);

  return (
    <div className="min-h-screen bg-gradient-to-br from-red-500 via-orange-500 to-amber-500 flex flex-col items-center justify-center p-4 font-sans text-white overflow-hidden relative">
      <PromptGuideModal isOpen={isGuideOpen} onClose={() => setIsGuideOpen(false)} />

      {/* Background Blobs for depth */}
      <div className="absolute top-20 left-20 w-72 h-72 bg-orange-600 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob"></div>
      <div className="absolute top-40 right-20 w-72 h-72 bg-red-600 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-2000"></div>
      <div className="absolute -bottom-8 left-40 w-72 h-72 bg-amber-600 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-4000"></div>

      <div className="w-full max-w-4xl relative z-10 flex flex-col h-[85vh]">

        {/* Main Glass Card */}
        <div className="flex-1 bg-white/10 backdrop-blur-xl border border-white/20 rounded-3xl shadow-2xl overflow-y-auto flex flex-col">

            <header className="p-6 md:p-8 border-b border-white/10 flex justify-between items-start">
               <div>
                 <h1 className="text-2xl font-bold text-white tracking-tight">Create a track</h1>
                 <p className="text-white/60 text-sm mt-1">Experiment with prompt, style, and instruments.</p>
               </div>
               <button onClick={() => setIsGuideOpen(true)} className="p-2 hover:bg-white/10 rounded-full transition-colors text-white/80">
                  <InfoIcon />
               </button>
            </header>

            <div className="p-6 md:p-8 space-y-8 flex-1">
                {error && (
                    <div className="bg-red-500/20 border border-red-500/40 text-red-100 px-4 py-3 rounded-xl text-sm backdrop-blur-sm">
                        {error}
                    </div>
                )}

                {/* Main Input Area */}
                <div className="relative group">
                    <textarea
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                        placeholder="Describe your sound..."
                        className="w-full bg-transparent text-3xl md:text-5xl font-bold text-white placeholder-white/30 focus:outline-none resize-none leading-tight"
                        rows={2}
                        disabled={isBusy}
                    />
                    <button 
                        onClick={handleSurpriseMe}
                        disabled={isBusy || isGeneratingPrompt}
                        className="absolute right-0 bottom-2 text-sm text-white/60 hover:text-white flex items-center gap-1 bg-white/10 px-3 py-1.5 rounded-full backdrop-blur-md transition-all hover:bg-white/20 disabled:opacity-50"
                    >
                        {isGeneratingPrompt ? <LoadingIcon /> : <MagicWandIcon />}
                        Surprise Me
                    </button>
                </div>

                {/* Controls Container */}
                <div className="flex flex-col gap-6">

                    {/* MultiSelect Instruments */}
                    <div className="w-full">
                        <MultiSelect 
                            options={INSTRUMENT_LIST}
                            selectedOptions={selectedInstruments}
                            onChange={setSelectedInstruments}
                            disabled={isBusy}
                        />
                    </div>

                    <div className="w-full h-px bg-white/10"></div>

                    {/* Parameters & Effects */}
                    <div className="flex flex-wrap gap-4 items-center">
                        <Slider label="BPM" min={60} max={200} step={1} value={musicConfig.bpm} onChange={v => setMusicConfig(c => ({...c, bpm: Math.round(v)}))} disabled={isBusy} />
                        <Slider label="Density" min={0} max={1} step={0.01} value={musicConfig.density} onChange={v => setMusicConfig(c => ({...c, density: v}))} disabled={isBusy} />
                        <Slider label="Guidance" min={0} max={6} step={0.1} value={musicConfig.guidance} onChange={v => setMusicConfig(c => ({...c, guidance: v}))} disabled={isBusy} />

                        {/* Effect Control Pill */}
                        <div className="flex items-center gap-2 bg-white/10 backdrop-blur-md rounded-full px-4 py-2 border border-white/20 shadow-sm">
                            <select 
                                value={effectType}
                                onChange={e => setEffectType(e.target.value as EffectType)}
                                disabled={!isBusy}
                                className="bg-transparent text-xs font-medium text-white/90 focus:outline-none cursor-pointer [&>option]:bg-gray-800"
                            >
                                <option value="none">No Effect</option>
                                <option value="reverb">Reverb</option>
                                <option value="echo">Echo</option>
                            </select>
                            {effectType !== 'none' && (
                                <input 
                                    type="range" 
                                    min={0} max={1} step={0.01} 
                                    value={effectIntensity} 
                                    onChange={e => setEffectIntensity(parseFloat(e.target.value))}
                                    className="w-16 h-1.5 bg-white/30 rounded-lg appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:h-3 [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-white"
                                />
                            )}
                        </div>
                    </div>
                </div>
            </div>

            {/* Bottom Player Bar */}
            <div className="p-4 md:p-6 bg-transparent">
                <div className="bg-black/80 backdrop-blur-2xl border border-white/10 rounded-full h-20 md:h-24 px-6 md:px-8 flex items-center gap-6 shadow-2xl relative z-20">

                    {/* Play/Stop Controls with Animation */}
                    <div className="flex items-center gap-4 relative">
                         {/* Pulse Ring Animation */}
                         {(status === 'generating') && (
                            <div className="absolute inset-0 rounded-full bg-orange-500/30 animate-ping scale-110 pointer-events-none"></div>
                         )}

                        {status === 'generating' || status === 'connecting' ? (
                             <button onClick={handleStop} className="relative z-10 w-12 h-12 md:w-14 md:h-14 bg-white text-black rounded-full flex items-center justify-center hover:scale-105 transition-transform shadow-lg shadow-white/20">
                                {status === 'connecting' ? <LoadingIcon /> : <StopIcon />}
                             </button>
                        ) : (
                             <button onClick={handleGenerate} disabled={!prompt} className="relative z-10 w-12 h-12 md:w-14 md:h-14 bg-white text-black rounded-full flex items-center justify-center hover:scale-105 transition-transform shadow-lg shadow-white/20 disabled:opacity-50 disabled:scale-100 disabled:cursor-not-allowed">
                                <PlayIcon />
                             </button>
                        )}

                        <button 
                            onClick={handleSurpriseMe} 
                            disabled={isBusy || isGeneratingPrompt}
                            className="p-3 text-white/50 hover:text-white hover:bg-white/10 rounded-full transition-all hidden md:block"
                            title="New Random Prompt"
                        >
                            <RefreshIcon />
                        </button>
                    </div>

                    {/* Visualizer Area */}
                    <div className="flex-1 h-full flex items-center justify-center overflow-hidden py-3">
                         {status === 'generating' && analyserRef.current ? (
                            <AudioVisualizer analyserNode={analyserRef.current} />
                         ) : (
                             <div className="flex items-center gap-1 h-8">
                                 {[...Array(20)].map((_, i) => (
                                     <div key={i} className="w-1.5 bg-white/10 rounded-full" style={{height: `${Math.random() * 40 + 20}%`}}></div>
                                 ))}
                             </div>
                         )}
                    </div>

                     {/* Export / Status Actions */}
                     <div className="flex items-center gap-4" ref={exportMenuRef}>
                        {isProcessingDownload ? (
                            <div className="w-10 h-10 flex items-center justify-center text-white/50"><LoadingIcon /></div>
                        ) : downloadUrl ? (
                            <div className="relative">
                                <button
                                    onClick={() => setIsExportMenuOpen(!isExportMenuOpen)}
                                    className={`flex items-center gap-2 p-3 ${isExportMenuOpen ? 'bg-white/20' : 'bg-white/10'} text-white rounded-full hover:bg-white/20 transition-all shadow-lg border border-white/5`}
                                    title="Export Options"
                                >
                                    <DownloadIcon />
                                    <ChevronDownIcon />
                                </button>

                                {isExportMenuOpen && (
                                    <div className="absolute bottom-full right-0 mb-3 w-56 bg-gray-900/95 backdrop-blur-xl border border-white/10 rounded-xl shadow-2xl overflow-hidden animate-fade-in-up">
                                        <div className="p-2">
                                            <div className="px-3 py-2 text-xs font-semibold text-white/40 uppercase tracking-wider">Export As</div>

                                            <a 
                                                href={downloadUrl} 
                                                download="gemini-music.wav"
                                                className="flex items-center justify-between w-full px-3 py-2.5 text-sm text-white hover:bg-white/10 rounded-lg transition-colors group"
                                                onClick={() => setIsExportMenuOpen(false)}
                                            >
                                                <span>WAV <span className="text-white/40 text-xs ml-1">(High Quality)</span></span>
                                                <svg className="w-4 h-4 text-white/0 group-hover:text-white/100 transition-colors" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                                            </a>

                                            <button 
                                                disabled
                                                className="flex items-center justify-between w-full px-3 py-2.5 text-sm text-white/40 cursor-not-allowed rounded-lg"
                                            >
                                                <span>MP3 <span className="text-white/20 text-xs ml-1">(Converting...)</span></span>
                                            </button>

                                            <button 
                                                disabled
                                                className="flex items-center justify-between w-full px-3 py-2.5 text-sm text-white/40 cursor-not-allowed rounded-lg"
                                            >
                                                <span>MIDI <span className="text-white/20 text-xs ml-1">(Not Supported)</span></span>
                                            </button>
                                        </div>
                                    </div>
                                )}
                            </div>
                        ) : null}
                     </div>

                </div>
            </div>
        </div>

        <p className="text-center text-white/40 text-xs mt-4">Powered by Gemini Live API</p>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { LiveMusicSession } from '@google/genai';
import { startSession, closeSession, updateMusicConfig, updatePrompt, generateSurprisePrompt } from './services/geminiService';
import { concatenateAudioBuffers, audioBufferToWav, createReverbImpulseResponse } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { LoadingIcon, PlayIcon, StopIcon, MagicWandIcon, DownloadIcon, InfoIcon, RefreshIcon, ChevronDownIcon } from './components/Icons';
import Slider from './components/Slider';
import PromptGuideModal from './components/PromptGuideModal';
import MultiSelect from './components/MultiSelect';

type Status = 'idle' | 'connecting' | 'generating' | 'stopping' | 'error';
type EffectType = 'none' | 'reverb' | 'echo';

interface MusicConfig {
  bpm: number;
  density: number;
  brightness: number;
  guidance: number;
}

const INSTRUMENT_LIST = [
    "Piano", "Acoustic Guitar", "Electric Guitar", "Bass Guitar", "Drums", "Violin", "Cello", "Trumpet",
    "Saxophone", "Flute", "Synth Pads", "808 Bass", "Sitar", "Marimba", "Hang Drum"
];

const App: React.FC = () => {
  const [prompt, setPrompt] = useState<string>('Minimal techno with deep bass');
  const [finalPrompt, setFinalPrompt] = useState(prompt);
  const [status, setStatus] = useState<Status>('idle');
  const [error, setError] = useState<string | null>(null);
  const [isGeneratingPrompt, setIsGeneratingPrompt] = useState(false);
  const [downloadUrl, setDownloadUrl] = useState<string | null>(null);
  const [isProcessingDownload, setIsProcessingDownload] = useState(false);
  const [isGuideOpen, setIsGuideOpen] = useState(false);
  const [selectedInstruments, setSelectedInstruments] = useState<string[]>([]);

  // Export Menu State
  const [isExportMenuOpen, setIsExportMenuOpen] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);

  const [musicConfig, setMusicConfig] = useState<MusicConfig>({
    bpm: 120,
    density: 0.5,
    brightness: 0.5,
    guidance: 4.0,
  });

  const [effectType, setEffectType] = useState<EffectType>('none');
  const [effectIntensity, setEffectIntensity] = useState(0.3); // Wet/Dry mix

  const sessionRef = useRef<LiveMusicSession | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef<number>(0);
  const audioChunksRef = useRef<AudioBuffer[]>([]);

  // Audio effects nodes
  const dryNodeRef = useRef<GainNode | null>(null);
  const wetNodeRef = useRef<GainNode | null>(null);
  const convolverNodeRef = useRef<ConvolverNode | null>(null); // Reverb
  const delayNodeRef = useRef<DelayNode | null>(null); // Echo
  const feedbackNodeRef = useRef<GainNode | null>(null); // Echo feedback
  const masterGainNodeRef = useRef<GainNode | null>(null);

  const statusRef = useRef(status);
  useEffect(() => {
    statusRef.current = status;
  }, [status]);

  const isBusy = status === 'connecting' || status === 'generating' || status === 'stopping';

  useEffect(() => {
    const url = downloadUrl;
    return () => {
        if (url) {
            URL.revokeObjectURL(url);
        }
    };
  }, [downloadUrl]);

  // Handle outside click for export menu
  useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
          if (exportMenuRef.current && !exportMenuRef.current.contains(event.target as Node)) {
              setIsExportMenuOpen(false);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const cleanupAudio = useCallback(() => {
    if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
      sourcesRef.current.forEach(source => {
        try {
            source.stop();
        } catch (e) {
            console.warn("Could not stop source", e);
        }
      });
      sourcesRef.current.clear();
      audioContextRef.current.close().catch(console.error);
    }
    audioContextRef.current = null;
    analyserRef.current = null;
    masterGainNodeRef.current = null;
    nextStartTimeRef.current = 0;
  }, []);

  const handleStop = useCallback(async () => {
    setStatus('stopping');
    if (sessionRef.current) {
      await closeSession(sessionRef.current);
      sessionRef.current = null;
    }

    if (audioChunksRef.current.length > 0) {
        setIsProcessingDownload(true);
        try {
            const concatenatedBuffer = concatenateAudioBuffers(audioChunksRef.current);
            if (concatenatedBuffer) {
                const wavBlob = audioBufferToWav(concatenatedBuffer);
                const url = URL.createObjectURL(wavBlob);
                setDownloadUrl(url);
            }
        } catch (e) {
            console.error("Failed to create download file:", e);
            setError("Could not process audio for download.");
        } finally {
            setIsProcessingDownload(false);
        }
    }

    cleanupAudio();
    setStatus('idle');
  }, [cleanupAudio]);

  const handleGenerate = useCallback(async () => {
    if (isBusy) return;
    setError(null);
    setDownloadUrl(null);
    setStatus('connecting');
    audioChunksRef.current = [];

    try {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 48000 });

      // Master Gain
      masterGainNodeRef.current = audioContext.createGain();

      // Analyser
      const analyser = audioContext.createAnalyser();
      analyser.fftSize = 256;
      masterGainNodeRef.current.connect(analyser);
      analyser.connect(audioContext.destination);

      // Effect nodes setup
      dryNodeRef.current = audioContext.createGain();
      wetNodeRef.current = audioContext.createGain();
      dryNodeRef.current.connect(masterGainNodeRef.current);
      wetNodeRef.current.connect(masterGainNodeRef.current);

      // Reverb
      convolverNodeRef.current = audioContext.createConvolver();
      const impulseResponse = await createReverbImpulseResponse(audioContext);
      convolverNodeRef.current.buffer = impulseResponse;

      // Echo
      delayNodeRef.current = audioContext.createDelay(1.0); // Max 1s delay
      feedbackNodeRef.current = audioContext.createGain();
      delayNodeRef.current.connect(feedbackNodeRef.current);
      feedbackNodeRef.current.connect(delayNodeRef.current);

      audioContextRef.current = audioContext;
      analyserRef.current = analyser;
      nextStartTimeRef.current = 0;
      sourcesRef.current.clear();

      const newSession = await startSession({
        prompt: finalPrompt,
        config: musicConfig,
        onAudioChunk: (audioBuffer) => {
          if (!audioContextRef.current || !masterGainNodeRef.current || !dryNodeRef.current) return;

          audioChunksRef.current.push(audioBuffer);

          const source = audioContextRef.current.createBufferSource();
          source.buffer = audioBuffer;
          // Connect source to both dry and wet paths
          source.connect(dryNodeRef.current);
          source.connect(wetNodeRef.current);

          source.onended = () => {
            sourcesRef.current.delete(source);
          };

          const currentTime = audioContextRef.current.currentTime;
          const startTime = Math.max(currentTime, nextStartTimeRef.current);
          source.start(startTime);
          nextStartTimeRef.current = startTime + audioBuffer.duration;
          sourcesRef.current.add(source);
        },
        onOpen: () => {
          setStatus('generating');
        },
        onError: (err: ErrorEvent) => {
          console.error('Session error:', err);
          setError(`An error occurred: ${err.message}. This might be an experimental feature. Please try again.`);
          setStatus('error');
          handleStop();
        },
        onClose: (_event: CloseEvent) => {
          if (statusRef.current !== 'stopping') {
            handleStop();
          }
        },
      });
      sessionRef.current = newSession;

    } catch (err: any) {
      console.error('Failed to start session:', err);
      setError(`Failed to start session: ${err.message}`);
      setStatus('error');
      cleanupAudio();
    }
  }, [finalPrompt, isBusy, cleanupAudio, handleStop, musicConfig]);

  const handleSurpriseMe = async () => {
    setIsGeneratingPrompt(true);
    setError(null);
    try {
        const newPrompt = await generateSurprisePrompt();
        setPrompt(newPrompt);
    } catch (err: any) {
        setError(`Failed to generate prompt: ${err.message}`);
    } finally {
        setIsGeneratingPrompt(false);
    }
  };

  useEffect(() => {
    const instrumentText = selectedInstruments.length > 0
        ? ` with the following instruments: ${selectedInstruments.join(', ')}.`
        : '';
    setFinalPrompt(prompt + instrumentText);
  }, [prompt, selectedInstruments]);


  useEffect(() => {
    if (status === 'generating' && sessionRef.current) {
        updateMusicConfig(sessionRef.current, musicConfig);
    }
  }, [musicConfig, status]);

  useEffect(() => {
    const handler = setTimeout(() => {
        if (status === 'generating' && sessionRef.current && finalPrompt) {
            updatePrompt(sessionRef.current, finalPrompt);
        }
    }, 500); // Debounce prompt updates

    return () => {
        clearTimeout(handler);
    };
  }, [finalPrompt, status]);

  // Effect routing logic
  useEffect(() => {
    if (status !== 'generating' || !wetNodeRef.current || !dryNodeRef.current || !masterGainNodeRef.current) return;

    // Disconnect all wet paths first
    wetNodeRef.current.disconnect();
    convolverNodeRef.current?.disconnect();
    delayNodeRef.current?.disconnect();
    feedbackNodeRef.current?.disconnect(delayNodeRef.current);

    // Set gains based on intensity (wet/dry mix)
    dryNodeRef.current.gain.setValueAtTime(1 - effectIntensity, audioContextRef.current!.currentTime);
    wetNodeRef.current.gain.setValueAtTime(effectIntensity, audioContextRef.current!.currentTime);

    if (effectType === 'reverb' && convolverNodeRef.current) {
        wetNodeRef.current.connect(convolverNodeRef.current);
        convolverNodeRef.current.connect(masterGainNodeRef.current);
    } else if (effectType === 'echo' && delayNodeRef.current && feedbackNodeRef.current) {
        // Intensity controls feedback and delay time for echo
        feedbackNodeRef.current.gain.setValueAtTime(effectIntensity * 0.7, audioContextRef.current!.currentTime); // 0.7 to avoid harsh feedback
        delayNodeRef.current.delayTime.setValueAtTime(effectIntensity * 0.5 + 0.1, audioContextRef.current!.currentTime); // 0.1s to 0.6s delay

        wetNodeRef.current.connect(delayNodeRef.current);
        delayNodeRef.current.connect(masterGainNodeRef.current);
        feedbackNodeRef.current.connect(delayNodeRef.current);
    } else {
        // No effect, set wet gain to 0
        wetNodeRef.current.gain.setValueAtTime(0, audioContextRef.current!.currentTime);
        dryNodeRef.current.gain.setValueAtTime(1, audioContextRef.current!.currentTime);
    }

  }, [effectType, effectIntensity, status]);

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-600 via-teal-500 to-emerald-500 flex flex-col items-center justify-center p-4 font-sans text-white overflow-hidden relative">
      <PromptGuideModal isOpen={isGuideOpen} onClose={() => setIsGuideOpen(false)} />

      {/* Background Blobs for depth */}
      <div className="absolute top-20 left-20 w-72 h-72 bg-teal-600 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob"></div>
      <div className="absolute top-40 right-20 w-72 h-72 bg-blue-600 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-2000"></div>
      <div className="absolute -bottom-8 left-40 w-72 h-72 bg-emerald-600 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-4000"></div>

      <div className="w-full max-w-4xl relative z-10 flex flex-col h-[85vh]">

        {/* Main Glass Card */}
        <div className="flex-1 bg-white/10 backdrop-blur-xl border border-white/20 rounded-3xl shadow-2xl overflow-y-auto flex flex-col">

            <header className="p-6 md:p-8 border-b border-white/10 flex justify-between items-start">
               <div>
                 <h1 className="text-2xl font-bold text-white tracking-tight">Create a track</h1>
                 <p className="text-white/60 text-sm mt-1">Experiment with prompt, style, and instruments.</p>
               </div>
               <button onClick={() => setIsGuideOpen(true)} className="p-2 hover:bg-white/10 rounded-full transition-colors text-white/80">
                  <InfoIcon />
               </button>
            </header>

            <div className="p-6 md:p-8 space-y-8 flex-1">
                {error && (
                    <div className="bg-red-500/20 border border-red-500/40 text-red-100 px-4 py-3 rounded-xl text-sm backdrop-blur-sm">
                        {error}
                    </div>
                )}

                {/* Main Input Area */}
                <div className="relative group">
                    <textarea
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                        placeholder="Describe your sound..."
                        className="w-full bg-transparent text-3xl md:text-5xl font-bold text-white placeholder-white/30 focus:outline-none resize-none leading-tight"
                        rows={2}
                        disabled={isBusy}
                    />
                    <button 
                        onClick={handleSurpriseMe}
                        disabled={isBusy || isGeneratingPrompt}
                        className="absolute right-0 bottom-2 text-sm text-white/60 hover:text-white flex items-center gap-1 bg-white/10 px-3 py-1.5 rounded-full backdrop-blur-md transition-all hover:bg-white/20 disabled:opacity-50"
                    >
                        {isGeneratingPrompt ? <LoadingIcon /> : <MagicWandIcon />}
                        Surprise Me
                    </button>
                </div>

                {/* Controls Container */}
                <div className="flex flex-col gap-6">

                    {/* MultiSelect Instruments */}
                    <div className="w-full">
                        <MultiSelect 
                            options={INSTRUMENT_LIST}
                            selectedOptions={selectedInstruments}
                            onChange={setSelectedInstruments}
                            disabled={isBusy}
                        />
                    </div>

                    <div className="w-full h-px bg-white/10"></div>

                    {/* Parameters & Effects */}
                    <div className="flex flex-wrap gap-4 items-center">
                        <Slider label="BPM" min={60} max={200} step={1} value={musicConfig.bpm} onChange={v => setMusicConfig(c => ({...c, bpm: Math.round(v)}))} disabled={isBusy} />
                        <Slider label="Density" min={0} max={1} step={0.01} value={musicConfig.density} onChange={v => setMusicConfig(c => ({...c, density: v}))} disabled={isBusy} />
                        <Slider label="Guidance" min={0} max={6} step={0.1} value={musicConfig.guidance} onChange={v => setMusicConfig(c => ({...c, guidance: v}))} disabled={isBusy} />

                        {/* Effect Control Pill */}
                        <div className="flex items-center gap-2 bg-white/10 backdrop-blur-md rounded-full px-4 py-2 border border-white/20 shadow-sm">
                            <select 
                                value={effectType}
                                onChange={e => setEffectType(e.target.value as EffectType)}
                                disabled={!isBusy}
                                className="bg-transparent text-xs font-medium text-white/90 focus:outline-none cursor-pointer [&>option]:bg-gray-800"
                            >
                                <option value="none">No Effect</option>
                                <option value="reverb">Reverb</option>
                                <option value="echo">Echo</option>
                            </select>
                            {effectType !== 'none' && (
                                <input 
                                    type="range" 
                                    min={0} max={1} step={0.01} 
                                    value={effectIntensity} 
                                    onChange={e => setEffectIntensity(parseFloat(e.target.value))}
                                    className="w-16 h-1.5 bg-white/30 rounded-lg appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:h-3 [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-white"
                                />
                            )}
                        </div>
                    </div>
                </div>
            </div>

            {/* Bottom Player Bar */}
            <div className="p-4 md:p-6 bg-transparent">
                <div className="bg-black/80 backdrop-blur-2xl border border-white/10 rounded-full h-20 md:h-24 px-6 md:px-8 flex items-center gap-6 shadow-2xl relative z-20">

                    {/* Play/Stop Controls with Animation */}
                    <div className="flex items-center gap-4 relative">
                         {/* Pulse Ring Animation */}
                         {(status === 'generating') && (
                            <div className="absolute inset-0 rounded-full bg-teal-500/30 animate-ping scale-110 pointer-events-none"></div>
                         )}

                        {status === 'generating' || status === 'connecting' ? (
                             <button onClick={handleStop} className="relative z-10 w-12 h-12 md:w-14 md:h-14 bg-white text-black rounded-full flex items-center justify-center hover:scale-105 transition-transform shadow-lg shadow-white/20">
                                {status === 'connecting' ? <LoadingIcon /> : <StopIcon />}
                             </button>
                        ) : (
                             <button onClick={handleGenerate} disabled={!prompt} className="relative z-10 w-12 h-12 md:w-14 md:h-14 bg-white text-black rounded-full flex items-center justify-center hover:scale-105 transition-transform shadow-lg shadow-white/20 disabled:opacity-50 disabled:scale-100 disabled:cursor-not-allowed">
                                <PlayIcon />
                             </button>
                        )}

                        <button 
                            onClick={handleSurpriseMe} 
                            disabled={isBusy || isGeneratingPrompt}
                            className="p-3 text-white/50 hover:text-white hover:bg-white/10 rounded-full transition-all hidden md:block"
                            title="New Random Prompt"
                        >
                            <RefreshIcon />
                        </button>
                    </div>

                    {/* Visualizer Area */}
                    <div className="flex-1 h-full flex items-center justify-center overflow-hidden py-3">
                         {status === 'generating' && analyserRef.current ? (
                            <AudioVisualizer analyserNode={analyserRef.current} />
                         ) : (
                             <div className="flex items-center gap-1 h-8">
                                 {[...Array(20)].map((_, i) => (
                                     <div key={i} className="w-1.5 bg-white/10 rounded-full" style={{height: `${Math.random() * 40 + 20}%`}}></div>
                                 ))}
                             </div>
                         )}
                    </div>

                     {/* Export / Status Actions */}
                     <div className="flex items-center gap-4" ref={exportMenuRef}>
                        {isProcessingDownload ? (
                            <div className="w-10 h-10 flex items-center justify-center text-white/50"><LoadingIcon /></div>
                        ) : downloadUrl ? (
                            <div className="relative">
                                <button
                                    onClick={() => setIsExportMenuOpen(!isExportMenuOpen)}
                                    className={`flex items-center gap-2 p-3 ${isExportMenuOpen ? 'bg-white/20' : 'bg-white/10'} text-white rounded-full hover:bg-white/20 transition-all shadow-lg border border-white/5`}
                                    title="Export Options"
                                >
                                    <DownloadIcon />
                                    <ChevronDownIcon />
                                </button>

                                {isExportMenuOpen && (
                                    <div className="absolute bottom-full right-0 mb-3 w-56 bg-gray-900/95 backdrop-blur-xl border border-white/10 rounded-xl shadow-2xl overflow-hidden animate-fade-in-up">
                                        <div className="p-2">
                                            <div className="px-3 py-2 text-xs font-semibold text-white/40 uppercase tracking-wider">Export As</div>

                                            <a 
                                                href={downloadUrl} 
                                                download="gemini-music.wav"
                                                className="flex items-center justify-between w-full px-3 py-2.5 text-sm text-white hover:bg-white/10 rounded-lg transition-colors group"
                                                onClick={() => setIsExportMenuOpen(false)}
                                            >
                                                <span>WAV <span className="text-white/40 text-xs ml-1">(High Quality)</span></span>
                                                <svg className="w-4 h-4 text-white/0 group-hover:text-white/100 transition-colors" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                                            </a>

                                            <button 
                                                disabled
                                                className="flex items-center justify-between w-full px-3 py-2.5 text-sm text-white/40 cursor-not-allowed rounded-lg"
                                            >
                                                <span>MP3 <span className="text-white/20 text-xs ml-1">(Converting...)</span></span>
                                            </button>

                                            <button 
                                                disabled
                                                className="flex items-center justify-between w-full px-3 py-2.5 text-sm text-white/40 cursor-not-allowed rounded-lg"
                                            >
                                                <span>MIDI <span className="text-white/20 text-xs ml-1">(Not Supported)</span></span>
                                            </button>
                                        </div>
                                    </div>
                                )}
                            </div>
                        ) : null}
                     </div>

                </div>
            </div>
        </div>

        <p className="text-center text-white/40 text-xs mt-4">Powered by Gemini Live API</p>
      </div>
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';

interface AudioVisualizerProps {
  analyserNode: AnalyserNode;
}

const AudioVisualizer: React.FC<AudioVisualizerProps> = ({ analyserNode }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameRef = useRef<number | null>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const canvasCtx = canvas.getContext('2d');
    if (!canvasCtx) return;

    const draw = () => {
      animationFrameRef.current = requestAnimationFrame(draw);

      const bufferLength = analyserNode.frequencyBinCount;
      const dataArray = new Uint8Array(bufferLength);
      analyserNode.getByteFrequencyData(dataArray);

      canvasCtx.clearRect(0, 0, canvas.width, canvas.height);

      const barWidth = (canvas.width / bufferLength) * 2;
      let x = 0;

      // Create a gradient that matches the "neon" aesthetic of the player
      const gradient = canvasCtx.createLinearGradient(0, 0, canvas.width, 0);
      gradient.addColorStop(0, '#14b8a6'); // Teal-500
      gradient.addColorStop(0.5, '#3b82f6'); // Blue-500
      gradient.addColorStop(1, '#10b981'); // Emerald-500

      canvasCtx.fillStyle = gradient;

      for (let i = 0; i < bufferLength; i++) {
        const barHeight = (dataArray[i] / 255) * canvas.height * 0.8; // Scale slightly

        // Center the bars vertically to look like a waveform
        const y = (canvas.height - barHeight) / 2;

        // Draw rounded bars
        canvasCtx.beginPath();
        canvasCtx.roundRect(x, y, barWidth - 1, barHeight, 2);
        canvasCtx.fill();

        x += barWidth + 1;
      }
    };

    draw();

    return () => {
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
      }
    };
  }, [analyserNode]);

  return <canvas ref={canvasRef} width="800" height="100" className="w-full h-full" />;
};

export default AudioVisualizer;

import React, { useState, useRef, useEffect } from 'react';
import { ChevronDownIcon, MusicNoteIcon } from './Icons';

interface MultiSelectProps {
  options: string[];
  selectedOptions: string[];
  onChange: (selected: string[]) => void;
  disabled?: boolean;
}

const MultiSelect: React.FC<MultiSelectProps> = ({ options, selectedOptions, onChange, disabled = false }) => {
  const [isOpen, setIsOpen] = useState(false);
  const wrapperRef = useRef<HTMLDivElement>(null);

  const toggleOption = (option: string) => {
    const newSelected = selectedOptions.includes(option)
      ? selectedOptions.filter((o) => o !== option)
      : [...selectedOptions, option];
    onChange(newSelected);
  };

  const removeOption = (e: React.MouseEvent, option: string) => {
      e.stopPropagation();
      onChange(selectedOptions.filter(o => o !== option));
  }

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  return (
    <div className="relative w-full md:w-auto" ref={wrapperRef}>
      <button
        type="button"
        onClick={() => !disabled && setIsOpen(!isOpen)}
        disabled={disabled}
        className={`w-full min-w-[200px] bg-white/5 border border-white/10 hover:bg-white/10 hover:border-white/20 transition-all rounded-xl px-4 py-2.5 text-left text-sm flex justify-between items-center disabled:opacity-50 disabled:cursor-not-allowed ${isOpen ? 'ring-2 ring-teal-500/50 border-transparent' : ''}`}
      >
        <span className="truncate text-white/80 font-medium flex items-center gap-2">
            <MusicNoteIcon />
            {selectedOptions.length === 0 ? 'Select instruments...' : `${selectedOptions.length} selected`}
        </span>
        <div className={`transition-transform duration-200 text-white/60 ${isOpen ? 'rotate-180' : ''}`}>
           <ChevronDownIcon />
        </div>
      </button>

      {/* Selected items display (Outside dropdown for cleaner look, similar to input tags) */}
      {selectedOptions.length > 0 && (
          <div className="flex flex-wrap gap-2 mt-3">
              {selectedOptions.map(option => (
                  <span key={option} className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-semibold bg-teal-500/80 text-white border border-teal-400/30 shadow-sm animate-fade-in-up">
                      {option}
                      <button 
                        onClick={(e) => removeOption(e, option)}
                        disabled={disabled}
                        className="hover:text-teal-200 focus:outline-none"
                      >
                          <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                      </button>
                  </span>
              ))}
          </div>
      )}

      {isOpen && (
        <div className="absolute z-50 w-full min-w-[240px] mt-2 bg-gray-900/95 backdrop-blur-xl border border-white/10 rounded-xl shadow-2xl max-h-60 overflow-y-auto custom-scrollbar animate-fade-in origin-top-left left-0">
          <div className="p-2 space-y-1">
            {options.map((option) => {
              const isSelected = selectedOptions.includes(option);
              return (
                <div
                  key={option}
                  onClick={() => toggleOption(option)}
                  className={`px-3 py-2 rounded-lg text-sm cursor-pointer flex items-center justify-between group transition-colors ${
                    isSelected 
                        ? 'bg-gradient-to-r from-teal-500/20 to-blue-500/20 text-white' 
                        : 'text-white/70 hover:bg-white/10 hover:text-white'
                  }`}
                >
                  <span className="font-medium">{option}</span>
                  {isSelected && (
                    <span className="text-teal-400">
                      <svg className="w-4 h-4" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                      </svg>
                    </span>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
};

export default MultiSelect;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { LiveMusicSession } from '@google/genai';
import { startSession, closeSession, updateMusicConfig, updatePrompt, generateSurprisePrompt } from './services/geminiService';
import { concatenateAudioBuffers, audioBufferToWav, createReverbImpulseResponse } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { LoadingIcon, PlayIcon, StopIcon, MagicWandIcon, DownloadIcon, InfoIcon, RefreshIcon, ChevronDownIcon } from './components/Icons';
import Slider from './components/Slider';
import PromptGuideModal from './components/PromptGuideModal';
import MultiSelect from './components/MultiSelect';

type Status = 'idle' | 'connecting' | 'generating' | 'stopping' | 'error';
type EffectType = 'none' | 'reverb' | 'echo';

interface MusicConfig {
  bpm: number;
  density: number;
  brightness: number;
  guidance: number;
}

const INSTRUMENT_LIST = [
    "Piano", "Acoustic Guitar", "Electric Guitar", "Bass Guitar", "Drums", "Violin", "Cello", "Trumpet",
    "Saxophone", "Flute", "Synth Pads", "808 Bass", "Sitar", "Marimba", "Hang Drum"
];

const App: React.FC = () => {
  const [prompt, setPrompt] = useState<string>('Minimal techno with deep bass');
  const [finalPrompt, setFinalPrompt] = useState(prompt);
  const [status, setStatus] = useState<Status>('idle');
  const [error, setError] = useState<string | null>(null);
  const [isGeneratingPrompt, setIsGeneratingPrompt] = useState(false);
  const [downloadUrl, setDownloadUrl] = useState<string | null>(null);
  const [isProcessingDownload, setIsProcessingDownload] = useState(false);
  const [isGuideOpen, setIsGuideOpen] = useState(false);
  const [selectedInstruments, setSelectedInstruments] = useState<string[]>([]);

  // Export Menu State
  const [isExportMenuOpen, setIsExportMenuOpen] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);

  const [musicConfig, setMusicConfig] = useState<MusicConfig>({
    bpm: 120,
    density: 0.5,
    brightness: 0.5,
    guidance: 4.0,
  });

  const [effectType, setEffectType] = useState<EffectType>('none');
  const [effectIntensity, setEffectIntensity] = useState(0.3); // Wet/Dry mix

  const sessionRef = useRef<LiveMusicSession | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef<number>(0);
  const audioChunksRef = useRef<AudioBuffer[]>([]);

  // Audio effects nodes
  const dryNodeRef = useRef<GainNode | null>(null);
  const wetNodeRef = useRef<GainNode | null>(null);
  const convolverNodeRef = useRef<ConvolverNode | null>(null); // Reverb
  const delayNodeRef = useRef<DelayNode | null>(null); // Echo
  const feedbackNodeRef = useRef<GainNode | null>(null); // Echo feedback
  const masterGainNodeRef = useRef<GainNode | null>(null);

  const statusRef = useRef(status);
  useEffect(() => {
    statusRef.current = status;
  }, [status]);

  const isBusy = status === 'connecting' || status === 'generating' || status === 'stopping';

  useEffect(() => {
    const url = downloadUrl;
    return () => {
        if (url) {
            URL.revokeObjectURL(url);
        }
    };
  }, [downloadUrl]);

  // Handle outside click for export menu
  useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
          if (exportMenuRef.current && !exportMenuRef.current.contains(event.target as Node)) {
              setIsExportMenuOpen(false);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const cleanupAudio = useCallback(() => {
    if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
      sourcesRef.current.forEach(source => {
        try {
            source.stop();
        } catch (e) {
            console.warn("Could not stop source", e);
        }
      });
      sourcesRef.current.clear();
      audioContextRef.current.close().catch(console.error);
    }
    audioContextRef.current = null;
    analyserRef.current = null;
    masterGainNodeRef.current = null;
    nextStartTimeRef.current = 0;
  }, []);

  const handleStop = useCallback(async () => {
    setStatus('stopping');
    if (sessionRef.current) {
      await closeSession(sessionRef.current);
      sessionRef.current = null;
    }

    if (audioChunksRef.current.length > 0) {
        setIsProcessingDownload(true);
        try {
            const concatenatedBuffer = concatenateAudioBuffers(audioChunksRef.current);
            if (concatenatedBuffer) {
                const wavBlob = audioBufferToWav(concatenatedBuffer);
                const url = URL.createObjectURL(wavBlob);
                setDownloadUrl(url);
            }
        } catch (e) {
            console.error("Failed to create download file:", e);
            setError("Could not process audio for download.");
        } finally {
            setIsProcessingDownload(false);
        }
    }

    cleanupAudio();
    setStatus('idle');
  }, [cleanupAudio]);

  const handleGenerate = useCallback(async () => {
    if (isBusy) return;
    setError(null);
    setDownloadUrl(null);
    setStatus('connecting');
    audioChunksRef.current = [];

    try {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 48000 });

      // Master Gain
      masterGainNodeRef.current = audioContext.createGain();

      // Analyser
      const analyser = audioContext.createAnalyser();
      analyser.fftSize = 256;
      masterGainNodeRef.current.connect(analyser);
      analyser.connect(audioContext.destination);

      // Effect nodes setup
      dryNodeRef.current = audioContext.createGain();
      wetNodeRef.current = audioContext.createGain();
      dryNodeRef.current.connect(masterGainNodeRef.current);
      wetNodeRef.current.connect(masterGainNodeRef.current);

      // Reverb
      convolverNodeRef.current = audioContext.createConvolver();
      const impulseResponse = await createReverbImpulseResponse(audioContext);
      convolverNodeRef.current.buffer = impulseResponse;

      // Echo
      delayNodeRef.current = audioContext.createDelay(1.0); // Max 1s delay
      feedbackNodeRef.current = audioContext.createGain();
      delayNodeRef.current.connect(feedbackNodeRef.current);
      feedbackNodeRef.current.connect(delayNodeRef.current);

      audioContextRef.current = audioContext;
      analyserRef.current = analyser;
      nextStartTimeRef.current = 0;
      sourcesRef.current.clear();

      const newSession = await startSession({
        prompt: finalPrompt,
        config: musicConfig,
        onAudioChunk: (audioBuffer) => {
          if (!audioContextRef.current || !masterGainNodeRef.current || !dryNodeRef.current) return;

          audioChunksRef.current.push(audioBuffer);

          const source = audioContextRef.current.createBufferSource();
          source.buffer = audioBuffer;
          // Connect source to both dry and wet paths
          source.connect(dryNodeRef.current);
          source.connect(wetNodeRef.current);

          source.onended = () => {
            sourcesRef.current.delete(source);
          };

          const currentTime = audioContextRef.current.currentTime;
          const startTime = Math.max(currentTime, nextStartTimeRef.current);
          source.start(startTime);
          nextStartTimeRef.current = startTime + audioBuffer.duration;
          sourcesRef.current.add(source);
        },
        onOpen: () => {
          setStatus('generating');
        },
        onError: (err: ErrorEvent) => {
          console.error('Session error:', err);
          setError(`An error occurred: ${err.message}. This might be an experimental feature. Please try again.`);
          setStatus('error');
          handleStop();
        },
        onClose: (_event: CloseEvent) => {
          if (statusRef.current !== 'stopping') {
            handleStop();
          }
        },
      });
      sessionRef.current = newSession;

    } catch (err: any) {
      console.error('Failed to start session:', err);
      setError(`Failed to start session: ${err.message}`);
      setStatus('error');
      cleanupAudio();
    }
  }, [finalPrompt, isBusy, cleanupAudio, handleStop, musicConfig]);

  const handleSurpriseMe = async () => {
    setIsGeneratingPrompt(true);
    setError(null);
    try {
        const newPrompt = await generateSurprisePrompt();
        setPrompt(newPrompt);
    } catch (err: any) {
        setError(`Failed to generate prompt: ${err.message}`);
    } finally {
        setIsGeneratingPrompt(false);
    }
  };

  useEffect(() => {
    const instrumentText = selectedInstruments.length > 0
        ? ` with the following instruments: ${selectedInstruments.join(', ')}.`
        : '';
    setFinalPrompt(prompt + instrumentText);
  }, [prompt, selectedInstruments]);


  useEffect(() => {
    if (status === 'generating' && sessionRef.current) {
        updateMusicConfig(sessionRef.current, musicConfig);
    }
  }, [musicConfig, status]);

  useEffect(() => {
    const handler = setTimeout(() => {
        if (status === 'generating' && sessionRef.current && finalPrompt) {
            updatePrompt(sessionRef.current, finalPrompt);
        }
    }, 500); // Debounce prompt updates

    return () => {
        clearTimeout(handler);
    };
  }, [finalPrompt, status]);

  // Effect routing logic
  useEffect(() => {
    if (status !== 'generating' || !wetNodeRef.current || !dryNodeRef.current || !masterGainNodeRef.current) return;

    // Disconnect all wet paths first
    wetNodeRef.current.disconnect();
    convolverNodeRef.current?.disconnect();
    delayNodeRef.current?.disconnect();
    feedbackNodeRef.current?.disconnect(delayNodeRef.current);

    // Set gains based on intensity (wet/dry mix)
    dryNodeRef.current.gain.setValueAtTime(1 - effectIntensity, audioContextRef.current!.currentTime);
    wetNodeRef.current.gain.setValueAtTime(effectIntensity, audioContextRef.current!.currentTime);

    if (effectType === 'reverb' && convolverNodeRef.current) {
        wetNodeRef.current.connect(convolverNodeRef.current);
        convolverNodeRef.current.connect(masterGainNodeRef.current);
    } else if (effectType === 'echo' && delayNodeRef.current && feedbackNodeRef.current) {
        // Intensity controls feedback and delay time for echo
        feedbackNodeRef.current.gain.setValueAtTime(effectIntensity * 0.7, audioContextRef.current!.currentTime); // 0.7 to avoid harsh feedback
        delayNodeRef.current.delayTime.setValueAtTime(effectIntensity * 0.5 + 0.1, audioContextRef.current!.currentTime); // 0.1s to 0.6s delay

        wetNodeRef.current.connect(delayNodeRef.current);
        delayNodeRef.current.connect(masterGainNodeRef.current);
        feedbackNodeRef.current.connect(delayNodeRef.current);
    } else {
        // No effect, set wet gain to 0
        wetNodeRef.current.gain.setValueAtTime(0, audioContextRef.current!.currentTime);
        dryNodeRef.current.gain.setValueAtTime(1, audioContextRef.current!.currentTime);
    }

  }, [effectType, effectIntensity, status]);

  return (
    <div className="min-h-screen bg-neutral-900 flex flex-col items-center justify-center p-4 font-sans overflow-hidden relative selection:bg-teal-500 selection:text-black">
      <PromptGuideModal isOpen={isGuideOpen} onClose={() => setIsGuideOpen(false)} />

      {/* Background Texture */}
      <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle at center, #333 1px, transparent 1px)', backgroundSize: '20px 20px' }}></div>
      <div className="absolute inset-0 bg-gradient-to-br from-neutral-800 via-neutral-900 to-black pointer-events-none"></div>

      {/* Main Synthesizer Chassis */}
      <div className="w-full max-w-5xl relative z-10 flex flex-col bg-neutral-800 rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.5),inset_0_1px_0_rgba(255,255,255,0.1),inset_0_0_0_1px_rgba(0,0,0,0.5)] border-t border-neutral-700 p-6 md:p-8">

        {/* Hardware Header */}
        <div className="flex justify-between items-center mb-6">
            <div className="flex items-center gap-3">
                {/* Power LED */}
                <div className={`w-3 h-3 rounded-full shadow-[0_0_10px_currentColor] transition-all duration-500 ${status === 'generating' ? 'bg-teal-400 text-teal-400 animate-pulse' : 'bg-red-900 text-red-900'}`}></div>
                <h1 className="text-xl font-bold text-neutral-400 tracking-widest uppercase font-mono">Gemini<span className="text-teal-500">Synth</span>-X1</h1>
            </div>
            <button onClick={() => setIsGuideOpen(true)} className="w-10 h-10 rounded-full bg-neutral-700 shadow-[0_2px_5px_rgba(0,0,0,0.3),inset_0_1px_0_rgba(255,255,255,0.1)] flex items-center justify-center text-neutral-400 hover:text-white active:shadow-[inset_0_2px_5px_rgba(0,0,0,0.5)] active:translate-y-px transition-all">
                  <InfoIcon />
            </button>
        </div>

        {/* Display Screen */}
        <div className="relative bg-black rounded-lg border-4 border-neutral-700 shadow-[inset_0_2px_10px_rgba(0,0,0,1)] mb-8 overflow-hidden">
            {/* Glossy Overlay */}
            <div className="absolute inset-0 bg-gradient-to-b from-white/5 to-transparent pointer-events-none z-20"></div>

            <div className="p-6 md:p-8 min-h-[240px] flex flex-col relative z-10">
                {error && (
                    <div className="mb-4 text-red-500 font-mono text-sm border border-red-900/50 bg-red-900/10 p-2 rounded">
                        ERROR: {error}
                    </div>
                )}

                {/* Main Input Area - VFD Display Style */}
                <div className="relative group flex-1">
                    <label className="text-xs text-teal-700 font-mono uppercase tracking-wider mb-1 block">Prompt Input</label>
                    <textarea
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                        placeholder="Initialize sound parameters..."
                        className="w-full bg-transparent text-2xl md:text-4xl font-mono text-teal-400 placeholder-teal-900 focus:outline-none resize-none leading-tight drop-shadow-[0_0_5px_rgba(45,212,191,0.5)]"
                        rows={2}
                        disabled={isBusy}
                        style={{ fontFamily: '"Courier New", Courier, monospace' }}
                    />

                    <div className="absolute right-0 bottom-2 flex gap-2">
                         <button 
                            onClick={handleSurpriseMe}
                            disabled={isBusy || isGeneratingPrompt}
                            className="text-xs text-teal-600 hover:text-teal-300 flex items-center gap-1 uppercase font-mono tracking-wider transition-colors disabled:opacity-50"
                        >
                            {isGeneratingPrompt ? <LoadingIcon /> : <MagicWandIcon />}
                            Randomize
                        </button>
                    </div>
                </div>
            </div>

             {/* Visualizer overlay on screen */}
             <div className="h-16 w-full bg-neutral-900/50 border-t border-neutral-800 relative overflow-hidden">
                  {/* Grid Lines */}
                  <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'linear-gradient(to right, #2dd4bf 1px, transparent 1px), linear-gradient(to bottom, #2dd4bf 1px, transparent 1px)', backgroundSize: '20px 20px' }}></div>

                  {status === 'generating' && analyserRef.current ? (
                        <div className="absolute inset-0 opacity-80 mix-blend-screen">
                            <AudioVisualizer analyserNode={analyserRef.current} />
                        </div>
                    ) : (
                         <div className="flex items-end justify-center gap-1 h-full pb-2 px-4 opacity-30">
                             {[...Array(40)].map((_, i) => (
                                 <div key={i} className="w-1.5 bg-teal-500" style={{height: `${Math.random() * 60 + 10}%`}}></div>
                             ))}
                         </div>
                    )}
             </div>
        </div>

        {/* Control Interface */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

            {/* Left Section: Transport & Instruments (4 cols) */}
            <div className="lg:col-span-5 flex flex-col gap-6">

                {/* Transport Controls */}
                <div className="bg-neutral-700/50 rounded-xl p-4 shadow-inner border border-neutral-600/50 flex items-center justify-between">
                     <div className="flex items-center gap-4">
                        {status === 'generating' || status === 'connecting' ? (
                             <button 
                                onClick={handleStop} 
                                className="w-16 h-16 rounded-full bg-gradient-to-b from-neutral-700 to-neutral-800 border-2 border-neutral-900 shadow-[0_4px_6px_rgba(0,0,0,0.5),inset_0_1px_0_rgba(255,255,255,0.1)] active:shadow-inner active:translate-y-0.5 flex items-center justify-center group"
                             >
                                <div className="text-red-500 drop-shadow-[0_0_5px_rgba(239,68,68,0.5)]">
                                    {status === 'connecting' ? <LoadingIcon /> : <StopIcon />}
                                </div>
                             </button>
                        ) : (
                             <button 
                                onClick={handleGenerate} 
                                disabled={!prompt} 
                                className="w-16 h-16 rounded-full bg-gradient-to-b from-neutral-200 to-neutral-400 border-4 border-neutral-300 shadow-[0_5px_10px_rgba(0,0,0,0.5)] active:shadow-[inset_0_3px_5px_rgba(0,0,0,0.4)] active:translate-y-0.5 flex items-center justify-center transition-all disabled:opacity-50 disabled:cursor-not-allowed group relative overflow-hidden"
                             >
                                <div className="absolute inset-0 bg-gradient-to-br from-transparent to-black/10 pointer-events-none"></div>
                                <div className="text-green-600 group-hover:text-green-500 drop-shadow-sm">
                                    <PlayIcon />
                                </div>
                             </button>
                        )}
                        <div className="flex flex-col">
                            <span className="text-[10px] uppercase font-bold text-neutral-500 tracking-widest mb-1">Status</span>
                            <div className="flex items-center gap-2">
                                <div className={`w-2 h-2 rounded-full ${status === 'idle' ? 'bg-neutral-600' : status === 'generating' ? 'bg-green-500 animate-pulse shadow-[0_0_5px_#22c55e]' : 'bg-yellow-500 animate-pulse'}`}></div>
                                <span className="text-xs font-mono text-neutral-300 uppercase">{status === 'idle' ? 'Ready' : status}</span>
                            </div>
                        </div>
                     </div>

                    <button 
                        onClick={handleSurpriseMe} 
                        disabled={isBusy || isGeneratingPrompt}
                        className="w-10 h-10 rounded bg-neutral-600 border-b-4 border-neutral-800 active:border-b-0 active:translate-y-1 transition-all shadow-lg flex items-center justify-center text-neutral-300 hover:text-white"
                        title="Randomize"
                    >
                        <RefreshIcon />
                    </button>
                </div>

                {/* Instrument Selector */}
                <div className="bg-neutral-700/30 rounded-xl p-4 border border-neutral-600/30">
                    <label className="text-[10px] uppercase font-bold text-neutral-400 tracking-widest mb-3 block">Instruments</label>
                    <MultiSelect 
                        options={INSTRUMENT_LIST}
                        selectedOptions={selectedInstruments}
                        onChange={setSelectedInstruments}
                        disabled={isBusy}
                    />
                </div>
            </div>

            {/* Middle Section: Sliders (5 cols) */}
            <div className="lg:col-span-5 bg-neutral-900/50 rounded-xl p-5 shadow-[inset_0_2px_4px_rgba(0,0,0,0.5)] border border-neutral-700">
                <div className="flex justify-between items-center mb-4">
                    <label className="text-[10px] uppercase font-bold text-neutral-400 tracking-widest">Parameters</label>
                    <div className="h-px flex-1 bg-neutral-700 ml-4"></div>
                </div>

                <div className="space-y-6">
                    <Slider label="BPM" min={60} max={200} step={1} value={musicConfig.bpm} onChange={v => setMusicConfig(c => ({...c, bpm: Math.round(v)}))} disabled={isBusy} />
                    <Slider label="Density" min={0} max={1} step={0.01} value={musicConfig.density} onChange={v => setMusicConfig(c => ({...c, density: v}))} disabled={isBusy} />
                    <Slider label="Guidance" min={0} max={6} step={0.1} value={musicConfig.guidance} onChange={v => setMusicConfig(c => ({...c, guidance: v}))} disabled={isBusy} />
                </div>
            </div>

            {/* Right Section: FX & Export (2 cols) */}
            <div className="lg:col-span-2 flex flex-col gap-4">

                 {/* FX Section */}
                 <div className="bg-neutral-700/30 rounded-xl p-3 border border-neutral-600/30 flex flex-col gap-3">
                    <label className="text-[10px] uppercase font-bold text-neutral-400 tracking-widest text-center">Master FX</label>

                    <div className="relative">
                        <select 
                            value={effectType}
                            onChange={e => setEffectType(e.target.value as EffectType)}
                            disabled={!isBusy}
                            className="w-full appearance-none bg-neutral-800 text-teal-400 text-xs font-mono border border-neutral-600 rounded px-2 py-2 focus:outline-none focus:border-teal-500 shadow-inner"
                        >
                            <option value="none">BYPASS</option>
                            <option value="reverb">REVERB</option>
                            <option value="echo">DELAY</option>
                        </select>
                        <div className="absolute right-2 top-2.5 pointer-events-none text-neutral-400">
                            <ChevronDownIcon />
                        </div>
                    </div>

                    <div className="flex items-center justify-center gap-2">
                         <span className="text-[9px] text-neutral-500 font-mono">DRY</span>
                         {effectType !== 'none' ? (
                             <input 
                                type="range" 
                                min={0} max={1} step={0.01} 
                                value={effectIntensity} 
                                onChange={e => setEffectIntensity(parseFloat(e.target.value))}
                                className="w-full h-1 bg-neutral-900 rounded-lg appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:h-3 [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-teal-500"
                             />
                         ) : (
                             <div className="w-full h-1 bg-neutral-800 rounded-lg"></div>
                         )}
                         <span className="text-[9px] text-neutral-500 font-mono">WET</span>
                    </div>
                 </div>

                 {/* Export Section */}
                 <div className="mt-auto flex justify-end" ref={exportMenuRef}>
                    {isProcessingDownload ? (
                        <div className="w-12 h-12 flex items-center justify-center text-teal-500 bg-neutral-800 rounded-lg border border-neutral-700 shadow-inner"><LoadingIcon /></div>
                    ) : downloadUrl ? (
                        <div className="relative w-full">
                            <button
                                onClick={() => setIsExportMenuOpen(!isExportMenuOpen)}
                                className={`w-full flex items-center justify-center gap-2 p-3 ${isExportMenuOpen ? 'bg-neutral-600' : 'bg-neutral-700'} text-neutral-200 rounded-lg hover:bg-neutral-600 transition-all shadow-[0_2px_4px_rgba(0,0,0,0.3)] border-b-2 border-neutral-900 active:border-b-0 active:translate-y-[2px]`}
                                title="Export Options"
                            >
                                <DownloadIcon />
                                <span className="text-xs font-bold uppercase">Save</span>
                            </button>

                            {isExportMenuOpen && (
                                <div className="absolute bottom-full right-0 mb-2 w-48 bg-neutral-800 border border-neutral-600 rounded-lg shadow-2xl overflow-hidden z-50">
                                    <div className="p-1">
                                        <div className="px-2 py-1 text-[10px] font-bold text-neutral-500 uppercase tracking-wider border-b border-neutral-700 mb-1">Format</div>

                                        <a 
                                            href={downloadUrl} 
                                            download="gemini-music.wav"
                                            className="flex items-center justify-between w-full px-3 py-2 text-xs font-mono text-teal-400 hover:bg-neutral-700 rounded transition-colors group"
                                            onClick={() => setIsExportMenuOpen(false)}
                                        >
                                            <span>WAV</span>
                                            <span className="text-[9px] text-neutral-500">48kHz</span>
                                        </a>

                                        <button disabled className="flex items-center justify-between w-full px-3 py-2 text-xs font-mono text-neutral-600 cursor-not-allowed">
                                            <span>MP3</span>
                                            <span className="text-[9px] text-neutral-700">N/A</span>
                                        </button>
                                    </div>
                                </div>
                            )}
                        </div>
                    ) : (
                         <div className="w-full h-12 border border-dashed border-neutral-700 rounded-lg flex items-center justify-center text-[10px] text-neutral-600 uppercase font-mono tracking-wider">
                            No Audio
                         </div>
                    )}
                 </div>

            </div>

        </div>

      </div>

      {/* Footer / Branding */}
      <div className="mt-8 flex items-center gap-2 opacity-30 text-xs font-mono text-neutral-500">
          <span>DESIGNED FOR</span>
          <span className="font-bold">GEMINI LIVE API</span>
          <span>//</span>
          <span>SYSTEM V1.0</span>
      </div>
    </div>
  );
};

export default App;

